Interactive: How Sample Size Affects the Estimate and SEM
Use the slider to change the sample size and observe how the sampling distribution, estimate, and SEM change. Each time, 500 samples of size n are drawn from a skewed population.

viewof sampleSize = Inputs.range([2, 200], {
  value: 10,
  step: 1,
  label: "Sample size (n):"
})







function mulberry32(a) {
  return function() {
    a |= 0; a = a + 0x6D2B79F5 | 0;
    var t = Math.imul(a ^ a &gt;&gt;&gt; 15, 1 | a);
    t = t + Math.imul(t ^ t &gt;&gt;&gt; 7, 61 | t) ^ t;
    return ((t ^ t &gt;&gt;&gt; 14) &gt;&gt;&gt; 0) / 4294967296;
  }
}

// Generate exponential random variable using inverse CDF
function randExp(rng, rate) {
  return -Math.log(1 - rng()) / rate;
}

// Generate population (exponential with rate=0.5, mean=2)
{
  const rng = mulberry32(12345);
  const popSize = 10000;
  const population = Array.from({length: popSize}, () =&gt; randExp(rng, 0.5));

  const trueMean = population.reduce((a, b) =&gt; a + b) / population.length;

  // Draw 500 samples of size n and compute means
  const nSamples = 500;
  const n = sampleSize;
  const sampleMeans = [];

  const sampleRng = mulberry32(42);
  for (let i = 0; i &lt; nSamples; i++) {
    let sum = 0;
    for (let j = 0; j &lt; n; j++) {
      const idx = Math.floor(sampleRng() * popSize);
      sum += population[idx];
    }
    sampleMeans.push(sum / n);
  }

  const grandMean = sampleMeans.reduce((a, b) =&gt; a + b) / sampleMeans.length;
  const variance = sampleMeans.reduce((a, b) =&gt; a + (b - grandMean) ** 2, 0) / (sampleMeans.length - 1);
  const sdMeans = Math.sqrt(variance);
  const sem = sdMeans / Math.sqrt(nSamples);
  const theoreticalSE = Math.sqrt(4) / Math.sqrt(n); // SD of Exp(0.5) = 1/rate = 2

  // Create histogram data
  const nBins = 35;
  const minVal = Math.min(...sampleMeans);
  const maxVal = Math.max(...sampleMeans);
  const padding = (maxVal - minVal) * 0.1;
  const binWidth = (maxVal - minVal + 2 * padding) / nBins;
  const bins = Array.from({length: nBins}, (_, i) =&gt; {
    const lo = minVal - padding + i * binWidth;
    const hi = lo + binWidth;
    const count = sampleMeans.filter(v =&gt; v &gt;= lo && v &lt; hi).length;
    return {lo, hi, mid: (lo + hi) / 2, count};
  });

  const maxCount = Math.max(...bins.map(b =&gt; b.count));

  return html`
    &lt;div style="display: flex; gap: 24px; align-items: flex-start; font-family: system-ui, sans-serif;"&gt;
      &lt;div style="flex: 1.3;"&gt;
        &lt;svg viewBox="0 0 500 300" style="width: 100%; max-width: 500px;"&gt;
          &lt;!-- Axes --&gt;
          &lt;line x1="60" y1="250" x2="480" y2="250" stroke="#333" stroke-width="1.5"/&gt;
          &lt;line x1="60" y1="250" x2="60" y2="20" stroke="#333" stroke-width="1.5"/&gt;

          &lt;!-- Title --&gt;
          &lt;text x="270" y="16" text-anchor="middle" font-size="14" font-weight="bold" fill="#333"&gt;
            Distribution of Sample Means (n = ${n})
          &lt;/text&gt;

          &lt;!-- Bars --&gt;
          ${bins.map(b =&gt; {
            const barH = maxCount &gt; 0 ? (b.count / maxCount) * 210 : 0;
            const x = 60 + ((b.lo - (minVal - padding)) / (maxVal - minVal + 2 * padding)) * 420;
            const w = (binWidth / (maxVal - minVal + 2 * padding)) * 420;
            return svg`&lt;rect x="${x}" y="${250 - barH}" width="${w - 1}" height="${barH}"
                          fill="#3498DB" opacity="0.85" stroke="white" stroke-width="0.5"/&gt;`;
          })}

          &lt;!-- Grand mean line --&gt;
          ${(() =&gt; {
            const x = 60 + ((grandMean - (minVal - padding)) / (maxVal - minVal + 2 * padding)) * 420;
            return svg`&lt;line x1="${x}" y1="250" x2="${x}" y2="25" stroke="#E74C3C" stroke-width="2.5"/&gt;`;
          })()}

          &lt;!-- True mean line --&gt;
          ${(() =&gt; {
            const x = 60 + ((trueMean - (minVal - padding)) / (maxVal - minVal + 2 * padding)) * 420;
            return svg`&lt;line x1="${x}" y1="250" x2="${x}" y2="25" stroke="#F39C12" stroke-width="2" stroke-dasharray="6,4"/&gt;`;
          })()}

          &lt;!-- SEM bracket --&gt;
          ${(() =&gt; {
            const cx = 60 + ((grandMean - (minVal - padding)) / (maxVal - minVal + 2 * padding)) * 420;
            const left = 60 + ((grandMean - sdMeans - (minVal - padding)) / (maxVal - minVal + 2 * padding)) * 420;
            const right = 60 + ((grandMean + sdMeans - (minVal - padding)) / (maxVal - minVal + 2 * padding)) * 420;
            const y = 32;
            return svg`
              &lt;line x1="${left}" y1="${y}" x2="${right}" y2="${y}" stroke="#2ECC71" stroke-width="2.5"/&gt;
              &lt;line x1="${left}" y1="${y-5}" x2="${left}" y2="${y+5}" stroke="#2ECC71" stroke-width="2"/&gt;
              &lt;line x1="${right}" y1="${y-5}" x2="${right}" y2="${y+5}" stroke="#2ECC71" stroke-width="2"/&gt;
              &lt;text x="${cx}" y="${y - 8}" text-anchor="middle" font-size="11" font-weight="bold" fill="#2ECC71"&gt;
                SD of means = ${sdMeans.toFixed(3)}
              &lt;/text&gt;
            `;
          })()}

          &lt;!-- X-axis labels --&gt;
          ${(() =&gt; {
            const range = maxVal - minVal + 2 * padding;
            const step = range / 5;
            return Array.from({length: 6}, (_, i) =&gt; {
              const val = minVal - padding + i * step;
              const x = 60 + (i / 5) * 420;
              return svg`&lt;text x="${x}" y="268" text-anchor="middle" font-size="10" fill="#666"&gt;${val.toFixed(1)}&lt;/text&gt;`;
            });
          })()}
          &lt;text x="270" y="290" text-anchor="middle" font-size="12" fill="#333"&gt;Sample Mean&lt;/text&gt;
          &lt;text x="25" y="140" text-anchor="middle" font-size="12" fill="#333" transform="rotate(-90,25,140)"&gt;Count&lt;/text&gt;
        &lt;/svg&gt;
      &lt;/div&gt;

      &lt;div style="flex: 0.7; padding-top: 20px;"&gt;
        &lt;div style="background: #f8f9fa; border-radius: 10px; padding: 18px; border: 1px solid #dee2e6;"&gt;
          &lt;div style="font-size: 14px; margin-bottom: 12px;"&gt;
            &lt;span style="display:inline-block; width:12px; height:3px; background:#E74C3C; margin-right:6px; vertical-align:middle;"&gt;&lt;/span&gt;
            &lt;strong&gt;Estimate (x̄):&lt;/strong&gt; ${grandMean.toFixed(3)}
          &lt;/div&gt;
          &lt;div style="font-size: 14px; margin-bottom: 12px;"&gt;
            &lt;span style="display:inline-block; width:12px; height:3px; background:#F39C12; margin-right:6px; vertical-align:middle; border-top: 2px dashed #F39C12;"&gt;&lt;/span&gt;
            &lt;strong&gt;True μ:&lt;/strong&gt; ${trueMean.toFixed(3)}
          &lt;/div&gt;
          &lt;div style="font-size: 14px; margin-bottom: 12px;"&gt;
            &lt;span style="display:inline-block; width:12px; height:3px; background:#2ECC71; margin-right:6px; vertical-align:middle;"&gt;&lt;/span&gt;
            &lt;strong&gt;SD of means:&lt;/strong&gt; ${sdMeans.toFixed(3)}
          &lt;/div&gt;
          &lt;div style="font-size: 14px; margin-bottom: 16px;"&gt;
            &lt;strong&gt;Theoretical SE:&lt;/strong&gt; σ/√n = ${theoreticalSE.toFixed(3)}
          &lt;/div&gt;
          &lt;hr style="border: none; border-top: 1px solid #dee2e6; margin: 12px 0;"&gt;
          &lt;div style="font-size: 13px; color: #555;"&gt;
            &lt;strong&gt;Key insight:&lt;/strong&gt;&lt;br&gt;
            As &lt;em&gt;n&lt;/em&gt; increases, the distribution narrows (SE ∝ 1/√n) and becomes more normal — regardless of population shape.
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  `;
}
